namespace std.sequence

# Creates an inclusive lazy range. It stores only its two bounds; each lowers
# consumption to a direct loop and never materializes an element array.
public range start: Int, endInclusive: Int -> Range {
    start..endInclusive
}

# Streams every projected Range value directly to the next pipeline consumer.
public map<R> values: Range -> stream R block item: Int -> R {
    values -> each item {
        item -> yield -> emit
    }
}

# Streams every projected growable-array value directly to the next consumer.
public mapArray<T, R> values: [T; ~] -> stream R block item: T -> R {
    values -> each item {
        item -> yield -> emit
    }
}

# Keeps only values accepted by the caller's predicate.
public filter<T> value: T -> stream T block item: T -> Bool {
    value -> yield => accepted
    accepted -> if {
        value -> emit
    }
}

# Observes a value without changing it.
public tap<T> value: T -> stream T block item: T -> Unit {
    value -> yield
    value -> emit
}

# Emits at most count values, then stops the complete upstream pipeline.
public take<T> value: T, count: Int -> stream T {
    state taken! = 0
    taken! < count -> if {
        taken! + 1 => taken!
        taken! >= count -> if {
            stop
        }
        value -> emit
    } else {
        stop
    }
}

# Discards the first count values and streams everything after them.
public skip<T> value: T, count: Int -> stream T {
    state skipped! = 0
    skipped! < count -> if {
        skipped! + 1 => skipped!
    } else {
        value -> emit
    }
}

# Carries one accumulator across the stream and emits every updated state.
public scan<T, S> value: T, initial: S -> stream S block accumulated: S, item: T -> S {
    state current! = initial
    current! -> yield(value) => current!
    current! -> emit
}

# Runs a block before each outer range item enters the downstream pipeline.
public beforeEach values: Range -> stream Int block item: Int -> Unit {
    values -> each item {
        item -> yield
        item -> emit
    }
}

# Runs a block after downstream processing for one item has completed.
public afterEach<T> value: T -> stream T block item: T -> Unit {
    value -> emit
    value -> yield
}

# Streams every projected inner item while retaining its outer value.
public flatMap<T, R> outer: T, innerValues: Range -> stream R block outerItem: T, inner: Int -> R {
    innerValues -> each inner {
        outer -> yield(inner) -> emit
    }
}

namespace sys.directory

import sys.path as path
import sys.directory.kind as kinds

# The runtime fills this private, length-prefixed byte snapshot in canonical
# name order. The public layer decodes it into independently owned entries, so
# no returned path borrows a native directory buffer or handle.
public struct Raw {
    bytes: [UInt8; ~]
    count: UIntSize
}

public struct Entry {
    name: path.Path
    kind: kinds.Kind
}

public enum RawResult {
    Ok(Raw)
    Err(Text)
}

public enum ReadResult {
    Ok([Entry; ~])
    Err(Text)
}

public readRaw directory: path.Path -> RawResult uses File = intrinsic

public rawByte raw: Raw, index: Int -> UInt8 => raw.bytes[index]

# Bootstrap consumers that cannot yet retain an owned enum payload may flatten
# the result immediately. A zero-count, one-byte snapshot is impossible for a
# native directory encoding and therefore preserves the read-failure state.
public readRawSnapshot directory: path.Path -> Raw {
    readRaw(directory) -> when {
        Ok(raw) {
            raw -> return
        }
        Err(error) {
            Raw { bytes: [UInt8(255), ~], count: UIntSize(0) } => failed!
            failed! -> return
        }
    }
    Raw { bytes: [UInt8(255), ~], count: UIntSize(0) } => unreachable!
    unreachable!
}

readError message: Text -> ReadResult {
    sys.directory.ReadResult.Err(message)
}

entryKind code: UInt8 -> kinds.Kind {
    code == UInt8(0) -> if {
        kinds.Kind.File
    } else {
        code == UInt8(1) -> if {
            kinds.Kind.Directory
        } else {
            code == UInt8(2) -> if {
                kinds.Kind.Symlink
            } else {
                kinds.Kind.Other
            }
        }
    }
}

# A directory read is an owned, deterministic snapshot. Entries are sorted by
# raw UTF-8 name bytes, exclude `.` and `..`, and never retain an OS handle.
public read directory: path.Path -> ReadResult {
    directory.style => style
    readRawSnapshot(directory) => raw!
    (raw!.count == UIntSize(0) and (raw!.bytes -> len) == 1) -> if {
        "io" -> readError => failure!
        failure! -> return
    }
    raw!.count => count
    [Entry; ~] => entries!
    UIntSize(0) => cursor!
    UIntSize(0) => entryIndex!
    entryIndex! < count -> while {
        raw! -> rawByte(Int(cursor!)) -> entryKind => kind
        cursor! + UIntSize(1) => cursor!
        UIntSize(raw! -> rawByte(Int(cursor!))) => length0
        UIntSize(raw! -> rawByte(Int(cursor! + UIntSize(1)))) * UIntSize(256) => length1
        UIntSize(raw! -> rawByte(Int(cursor! + UIntSize(2)))) * UIntSize(65536) => length2
        UIntSize(raw! -> rawByte(Int(cursor! + UIntSize(3)))) * UIntSize(16777216) => length3
        length0 + length1 + length2 + length3 => nameLength
        cursor! + UIntSize(4) => cursor!
        [UInt8; ~] => nameBytes!
        UIntSize(0) => nameIndex!
        nameIndex! < nameLength -> while {
            nameBytes! -> push(raw! -> rawByte(Int(cursor! + nameIndex!)))
            nameIndex! + UIntSize(1) => nameIndex!
        }
        cursor! + nameLength => cursor!
        entries! -> push(Entry {
            name: path.Path { bytes: nameBytes!, style: style }
            kind: kind
        })
        entryIndex! + UIntSize(1) => entryIndex!
    }
    sys.directory.ReadResult.Ok(entries!)
}

namespace sys.directory.kind

public enum Kind {
    File
    Directory
    Symlink
    Other
}

public code kind: Kind -> Int => kind -> when {
    File => 0
    Directory => 1
    Symlink => 2
    Other => 3
}

namespace sys.file

import sys.runtime as rt
import sys.path as path

# File is an affine native resource. Its private token cannot be constructed or
# copied by user code, and leaving the owner scope closes it deterministically.
public struct File {
    token: UInt64
}

# FileWriter is a separate affine capability, so read-only and write-only
# handles cannot be mixed accidentally. openWrite creates or truncates a file.
# Its syncAsync flow member is a durable-data barrier, not a user-buffer flush.
public struct FileWriter {
    token: UInt64
}

public struct AtomicReplaceRequest {
    temporary: Text
    destination: Text
}

# SourceText is an affine compiler input. A borrowed literal has no mapping;
# a mapped file owns its mapping until the SourceText owner is dropped.
public struct SourceText {
    token: UInt64
}

# User-defined values opt into binary serialization by constructing their own
# canonical byte representation. This deliberately avoids writing a struct's
# target-dependent in-memory ABI layout.
public trait BinarySerializable {
    serialize: self -> [UInt8; ~]
}

borrowText text: Text -> SourceText = intrinsic

mapText path: Text -> SourceText uses File = intrinsic

# Maps an owned target-explicit Path without manufacturing a Text view whose
# lifetime could outlive the Path storage.
public mapPath value: path.Path -> SourceText uses File = intrinsic

public openRead path: Text -> Result<File, Text> uses File = intrinsic

public openReadAsync path: Text -> async Result<File, Text> uses File = intrinsic

public openWrite path: Text -> Result<FileWriter, Text> uses File = intrinsic

public openWriteAsync path: Text -> async Result<FileWriter, Text> uses File = intrinsic

# Synchronous compiler/cache durability primitives. The affine writer closes
# deterministically at scope exit before atomicReplace publishes its temp file.
public sync writer: FileWriter -> Bool uses File = intrinsic

public atomicReplace request: AtomicReplaceRequest -> Bool uses File = intrinsic

openIntWriter path: Text -> Unit uses File {
    path -> rt.openIntWriter
}

writeInt value: Int -> Unit uses File {
    value -> rt.writeInt
}

closeIntWriter: -> Unit uses File {
    rt.closeIntWriter
}

openIntReader path: Text -> Unit uses File {
    path -> rt.openIntReader
}

closestInt target: Int -> Int uses File {
    target -> rt.closestInt
}

closeIntReader: -> Unit uses File {
    rt.closeIntReader
}

# Generic canonical binary writer. Existing Int-specific names remain for the
# sorted Int64 demo format.
openWriter path: Text -> Unit uses File = intrinsic

write<T> value: T -> Unit uses File = intrinsic

closeWriter: -> Unit uses File = intrinsic

# Generic canonical binary reader. Ok(None) is clean EOF; partial scalars,
# invalid Bool/CodePoint encodings, and operating-system failures return
# "truncated", "invalid", and "io" errors.
openReader path: Text -> Unit uses File = intrinsic

read<T>: -> Result<Option<T>, Text> uses File = intrinsic

# Asynchronous scalar reads use the shared native file worker. The operation
# returns an affine Task and therefore composes with the ordinary await and
# cancellation rules without exposing callbacks or executor handles.
readAsync<T>: -> async Result<Option<T>, Text> uses File = intrinsic

closeReader: -> Unit uses File = intrinsic

namespace sys.io

import sys.runtime as rt

print value: Text -> Unit uses Console {
    value -> rt.print
}

println value: Text -> Unit uses Console {
    value -> rt.println
}

readInt prompt: Text -> Int uses Console {
    prompt -> rt.readInt
}

namespace sys.path

import sys.directory.kind as kinds

# Path owns its UTF-8 storage. It is not a Text alias and therefore cannot
# outlive borrowed source storage accidentally.
public struct Path {
    bytes: [UInt8; ~]
    style: Style
}

# A query follows symbolic links and returns one owned canonical path together
# with the portable metadata shared by Windows and Linux.
public struct RawInfo {
    bytes: [UInt8; ~]
    kindCode: UInt8
    byteLength: UInt64
    modifiedNanos: UInt64
}

public struct Info {
    canonical: Path
    kind: kinds.Kind
    byteLength: UInt64
    modifiedNanos: UInt64
}

# Path style is explicit so a cross-compiler can manipulate target paths
# without silently applying the host machine's separator rules.
public enum Style {
    Posix
    Windows
}

public queryRaw target: Path -> Result<RawInfo, Text> uses File = intrinsic

queryKind code: UInt8 -> kinds.Kind {
    code == UInt8(0) -> if {
        kinds.Kind.File
    } else {
        code == UInt8(1) -> if {
            kinds.Kind.Directory
        } else {
            code == UInt8(2) -> if {
                kinds.Kind.Symlink
            } else {
                kinds.Kind.Other
            }
        }
    }
}

copyBytes source: [UInt8; ~] -> [UInt8; ~] {
    [UInt8; ~] => copied!
    0 => index!
    index! < (source -> len) -> while {
        copied! -> push(source[index!])
        index! + 1 => index!
    }
    copied!
}

public query target: Path -> Result<Info, Text> uses File {
    target.style => style
    target -> queryRaw -> when {
        Ok(raw) {
            raw.bytes -> copyBytes => canonicalBytes!
            Info {
                canonical: Path { bytes: canonicalBytes!, style: style }
                kind: raw.kindCode -> queryKind
                byteLength: raw.byteLength
                modifiedNanos: raw.modifiedNanos
            } => info!
            Result<Info, Text>.Ok(info!) -> return
        }
        Err(error) {
            Result<Info, Text>.Err(error) -> return
        }
    }
    Result<Info, Text>.Err("io")
}

# The compiled target decides this value; it never reflects the build host.
public nativeStyle: -> Style = intrinsic

sameStyle left: Style, right: Style -> Bool {
    left -> when {
        Posix {
            right -> when {
                Posix { true }
                Windows { false }
            }
        }
        Windows {
            right -> when {
                Posix { false }
                Windows { true }
            }
        }
    }
}

isSeparator value: UInt8, style: Style -> Bool {
    style -> when {
        Posix { value == UInt8(47) }
        Windows { value == UInt8(47) or value == UInt8(92) }
    }
}

pathError message: Text -> Result<Path, Text> {
    Result<Path, Text>.Err(message) => result!
    result!
}

public fromText value: Text, style: Style -> Path {
    [UInt8; ~] => bytes!
    UIntSize(0) => index!
    index! < (value -> len) -> while {
        bytes! -> push(value -> byte(index!))
        index! + UIntSize(1) => index!
    }
    Path { bytes: bytes!, style: style } => result!
    result!
}

public byteCount path: Path -> UIntSize {
    UIntSize(path.bytes -> len)
}

public equalsText path: Path, value: Text -> Bool {
    UIntSize(path.bytes -> len) => pathLength
    value -> len => valueLength
    pathLength == valueLength => matches!
    UIntSize(0) => index!
    (matches! and index! < pathLength) -> while {
        path.bytes[Int(index!)] != (value -> byte(index!)) -> if { false => matches! }
        index! + UIntSize(1) => index!
    }
    matches!
}

public endsWithText path: Path, value: Text -> Bool {
    UIntSize(path.bytes -> len) => pathLength
    value -> len => valueLength
    valueLength <= pathLength => matches!
    pathLength - valueLength => start
    UIntSize(0) => index!
    (matches! and index! < valueLength) -> while {
        path.bytes[Int(start + index!)] != (value -> byte(index!)) -> if { false => matches! }
        index! + UIntSize(1) => index!
    }
    matches!
}

public isAbsolute path: Path -> Bool {
    path.style -> when {
        Posix {
            UIntSize(path.bytes -> len) > UIntSize(0) and path.bytes[0] == UInt8(47)
        }
        Windows {
            UIntSize(path.bytes -> len) => length
            false => absolute!
            (length >= UIntSize(2) and (path.bytes[0] == UInt8(47) or path.bytes[0] == UInt8(92)) and (path.bytes[1] == UInt8(47) or path.bytes[1] == UInt8(92))) -> if { true => absolute! }
            (length >= UIntSize(3) and path.bytes[1] == UInt8(58) and (path.bytes[2] == UInt8(47) or path.bytes[2] == UInt8(92))) -> if { true => absolute! }
            absolute!
        }
    }
}

# Join rejects an absolute child rather than silently discarding the base.
public join base: move Path, child: Text -> Result<Path, Text> {
    base.style => style
    style -> when {
        Posix {
            (child -> len) > UIntSize(0) and (child -> byte(UIntSize(0))) == UInt8(47)
        }
        Windows {
            child -> len => childLength
            false => absolute!
            (childLength >= UIntSize(2) and ((child -> byte(UIntSize(0))) == UInt8(47) or (child -> byte(UIntSize(0))) == UInt8(92)) and ((child -> byte(UIntSize(1))) == UInt8(47) or (child -> byte(UIntSize(1))) == UInt8(92))) -> if { true => absolute! }
            (childLength >= UIntSize(3) and (child -> byte(UIntSize(1))) == UInt8(58) and ((child -> byte(UIntSize(2))) == UInt8(47) or (child -> byte(UIntSize(2))) == UInt8(92))) -> if { true => absolute! }
            absolute!
        }
    } => childAbsolute
    childAbsolute -> if {
        pathError("absolute child path") -> return
    }
    base.bytes => bytes!
    UIntSize(bytes! -> len) => baseLength
    false => endsWithSeparator!
    baseLength > UIntSize(0) -> if {
        bytes![Int(baseLength - UIntSize(1))] => lastByte
        style -> when {
            Posix => lastByte == UInt8(47)
            Windows => lastByte == UInt8(47) or lastByte == UInt8(92)
        } => endsWithSeparator!
    }
    (baseLength > UIntSize(0) and (child -> len) > UIntSize(0) and not endsWithSeparator!) -> if {
        style -> when {
            Posix => UInt8(47)
            Windows => UInt8(92)
        } => separator
        bytes! -> push(separator)
    }
    UIntSize(0) => childIndex!
    childIndex! < (child -> len) -> while {
        bytes! -> push(child -> byte(childIndex!))
        childIndex! + UIntSize(1) => childIndex!
    }
    Path { bytes: bytes!, style: style } => joined!
    Result<Path, Text>.Ok(joined!)
}

# Joins two owned path values without borrowing either result from the inputs.
# The returned Path owns a fresh byte buffer, so directory Entry values can be
# dropped immediately after source-root discovery advances.
public joinDiscovered base: Path, child: Path -> Path {
    [UInt8; ~] => bytes!
    UIntSize(0) => baseIndex!
    baseIndex! < UIntSize(base.bytes -> len) -> while {
        bytes! -> push(base.bytes[Int(baseIndex!)])
        baseIndex! + UIntSize(1) => baseIndex!
    }
    UIntSize(bytes! -> len) => baseLength
    false => endsWithSeparator!
    baseLength > UIntSize(0) -> if {
        bytes![Int(baseLength - UIntSize(1))] => last
        isSeparator(last, base.style) => endsWithSeparator!
    }
    (baseLength > UIntSize(0) and UIntSize(child.bytes -> len) > UIntSize(0) and not endsWithSeparator!) -> if {
        base.style -> when {
            Posix => UInt8(47)
            Windows => UInt8(92)
        } => separator
        bytes! -> push(separator)
    }
    UIntSize(0) => childIndex!
    childIndex! < UIntSize(child.bytes -> len) -> while {
        bytes! -> push(child.bytes[Int(childIndex!)])
        childIndex! + UIntSize(1) => childIndex!
    }
    Path { bytes: bytes!, style: base.style } => joined!
    joined!
}

public joinPath base: Path, child: Path -> Result<Path, Text> {
    not sameStyle(base.style, child.style) -> if {
        Result<Path, Text>.Err("path styles differ") -> return
    }
    child -> isAbsolute -> if {
        Result<Path, Text>.Err("cannot join an absolute child") -> return
    }

    base -> joinDiscovered(child) => joined!
    Result<Path, Text>.Ok(joined!)
}

# Lexical normalization never touches the filesystem. Parent components that
# would cross the starting root are rejected, which is the safe default for
# package roots and module discovery.
public normalizeConfined path: move Path -> Result<Path, Text> {
    path.style => style
    path.bytes => source!
    [UInt8; ~] => output!
    [UIntSize; ~] => componentStarts!
    style -> when {
        Posix => false
        Windows => true
    } => windows
    UIntSize(source! -> len) => sourceLength
    UIntSize(0) => index!
    false => absolute!
    false => unc!
    UIntSize(0) => protectedComponents!

    windows -> if {
        (sourceLength >= UIntSize(2) and source![1] == UInt8(58)) -> if {
            output! -> push(source![0])
            output! -> push(UInt8(58))
            UIntSize(2) => index!
            (index! < sourceLength and (source![Int(index!)] == UInt8(47) or source![Int(index!)] == UInt8(92))) -> if {
                output! -> push(UInt8(92))
                true => absolute!
                (index! < sourceLength and (source![Int(index!)] == UInt8(47) or source![Int(index!)] == UInt8(92))) -> while { index! + UIntSize(1) => index! }
            }
        } else {
            (sourceLength >= UIntSize(2) and (source![0] == UInt8(47) or source![0] == UInt8(92)) and (source![1] == UInt8(47) or source![1] == UInt8(92))) -> if {
                output! -> push(UInt8(92))
                output! -> push(UInt8(92))
                true => absolute!
                true => unc!
                UIntSize(2) => protectedComponents!
                UIntSize(2) => index!
                (index! < sourceLength and (source![Int(index!)] == UInt8(47) or source![Int(index!)] == UInt8(92))) -> while { index! + UIntSize(1) => index! }
            }
        }
    } else {
        (sourceLength > UIntSize(0) and source![0] == UInt8(47)) -> if {
            output! -> push(UInt8(47))
            true => absolute!
            UIntSize(1) => index!
            (index! < sourceLength and source![Int(index!)] == UInt8(47)) -> while { index! + UIntSize(1) => index! }
        }
    }

    false => escaped!
    false => wroteComponent!
    (index! < sourceLength and not escaped!) -> while {
        index! => componentStart
        (index! < sourceLength and (windows -> if { source![Int(index!)] != UInt8(47) and source![Int(index!)] != UInt8(92) } else { source![Int(index!)] != UInt8(47) })) -> while {
            index! + UIntSize(1) => index!
        }
        index! => componentEnd
        componentEnd - componentStart => componentLength
        (index! < sourceLength and (windows -> if { source![Int(index!)] == UInt8(47) or source![Int(index!)] == UInt8(92) } else { source![Int(index!)] == UInt8(47) })) -> while {
            index! + UIntSize(1) => index!
        }

        componentLength == UIntSize(1) and source![Int(componentStart)] == UInt8(46) => currentDirectory
        componentLength == UIntSize(2) and source![Int(componentStart)] == UInt8(46) and source![Int(componentStart + UIntSize(1))] == UInt8(46) => parentDirectory
        (componentLength > UIntSize(0) and not currentDirectory and not parentDirectory) -> if {
            UIntSize(output! -> len) => truncateStart
            wroteComponent! -> if {
                windows -> if { output! -> push(UInt8(92)) } else { output! -> push(UInt8(47)) }
            }
            componentStarts! -> push(truncateStart)
            componentStart => componentByteIndex!
            componentByteIndex! < componentEnd -> while {
                output! -> push(source![Int(componentByteIndex!)])
                componentByteIndex! + UIntSize(1) => componentByteIndex!
            }
            true => wroteComponent!
        }
        parentDirectory -> if {
            UIntSize(componentStarts! -> len) > protectedComponents! -> if {
                componentStarts! -> take(Int(UIntSize(componentStarts! -> len) - UIntSize(1))) => truncateTo
                UIntSize(output! -> len) > truncateTo -> while {
                    output! -> take(Int(UIntSize(output! -> len) - UIntSize(1))) => removedByte
                }
                UIntSize(componentStarts! -> len) > UIntSize(0) => wroteComponent!
            } else {
                true => escaped!
            }
        }
    }

    escaped! -> if {
        pathError("path escapes root") -> return
    }
    (unc! and UIntSize(componentStarts! -> len) < UIntSize(2)) -> if {
        pathError("incomplete UNC path") -> return
    }
    UIntSize(output! -> len) == UIntSize(0) -> if { output! -> push(UInt8(46)) }
    Path { bytes: output!, style: style } => normalized!
    Result<Path, Text>.Ok(normalized!)
}

namespace sys.random

import sys.runtime as rt

seed value: Int -> Unit uses Random {
    value -> rt.seedRandom
}

below maxExclusive: Int -> Int uses Random {
    maxExclusive -> rt.randomBelow
}

namespace sys.text

# Text exposes UTF-8 storage size explicitly. Code-point iteration remains a
# distinct operation, so byte-oriented compiler code never confuses the two.
public byteCount value: Text -> UIntSize {
    value -> len
}

public isEmpty value: Text -> Bool {
    (value -> len) == UIntSize(0)
}

# Text search reports UTF-8 byte offsets. This keeps compiler-facing path and
# source operations allocation-free and makes the offset unit explicit.
public startsWith value: Text, prefix: Text -> Bool {
    value -> len => valueLength
    prefix -> len => prefixLength
    prefixLength <= valueLength => matches!
    UIntSize(0) => index!
    (matches! and index! < prefixLength) -> while {
        (value -> byte(index!)) != (prefix -> byte(index!)) -> if { false => matches! }
        index! + UIntSize(1) => index!
    }
    matches!
}

public endsWith value: Text, suffix: Text -> Bool {
    value -> len => valueLength
    suffix -> len => suffixLength
    suffixLength <= valueLength => matches!
    UIntSize(0) => start!
    matches! -> if { valueLength - suffixLength => start! }
    UIntSize(0) => index!
    (matches! and index! < suffixLength) -> while {
        (value -> byte(start! + index!)) != (suffix -> byte(index!)) -> if { false => matches! }
        index! + UIntSize(1) => index!
    }
    matches!
}

public indexOf value: Text, needle: Text -> Option<UIntSize> {
    value -> len => valueLength
    needle -> len => needleLength
    UIntSize(0) => start!
    false => found!
    (needleLength > UIntSize(0) and needleLength <= valueLength) -> if {
        (not found! and start! + needleLength <= valueLength) -> while {
            true => matches!
            UIntSize(0) => index!
            (matches! and index! < needleLength) -> while {
                (value -> byte(start! + index!)) != (needle -> byte(index!)) -> if { false => matches! }
                index! + UIntSize(1) => index!
            }
            matches! -> if { true => found! } else { start! + UIntSize(1) => start! }
        }
    }
    found! -> if { Option<UIntSize>.Some(start!) } else { Option<UIntSize>.None }
}

public lastIndexOf value: Text, needle: Text -> Option<UIntSize> {
    value -> len => valueLength
    needle -> len => needleLength
    UIntSize(0) => result!
    false => found!
    UIntSize(0) => start!
    (needleLength > UIntSize(0) and needleLength <= valueLength) -> if {
        start! + needleLength <= valueLength -> while {
            true => matches!
            UIntSize(0) => index!
            (matches! and index! < needleLength) -> while {
                (value -> byte(start! + index!)) != (needle -> byte(index!)) -> if { false => matches! }
                index! + UIntSize(1) => index!
            }
            matches! -> if {
                start! => result!
                true => found!
            }
            start! + UIntSize(1) => start!
        }
    }
    found! -> if { Option<UIntSize>.Some(result!) } else { Option<UIntSize>.None }
}

public contains value: Text, needle: Text -> Bool {
    value -> len => valueLength
    needle -> len => needleLength
    UIntSize(0) => start!
    false => found!
    (needleLength > UIntSize(0) and needleLength <= valueLength) -> if {
        (not found! and start! + needleLength <= valueLength) -> while {
            true => matches!
            UIntSize(0) => index!
            (matches! and index! < needleLength) -> while {
                (value -> byte(start! + index!)) != (needle -> byte(index!)) -> if { false => matches! }
                index! + UIntSize(1) => index!
            }
            matches! -> if { true => found! } else { start! + UIntSize(1) => start! }
        }
    }
    found!
}

public compareOrdinal left: Text, right: Text -> Int {
    left -> len => leftLength
    right -> len => rightLength
    leftLength < rightLength -> if { leftLength } else { rightLength } => sharedLength
    UIntSize(0) => index!
    0 => result!
    (result! == 0 and index! < sharedLength) -> while {
        left -> byte(index!) => leftByte
        right -> byte(index!) => rightByte
        leftByte < rightByte -> if { -1 => result! }
        leftByte > rightByte -> if { 1 => result! }
        index! + UIntSize(1) => index!
    }
    result! == 0 -> if {
        leftLength < rightLength -> if { -1 => result! }
        leftLength > rightLength -> if { 1 => result! }
    }
    result!
}

public equalsAsciiIgnoreCase left: Text, right: Text -> Bool {
    left -> len => leftLength
    right -> len => rightLength
    leftLength == rightLength => matches!
    UIntSize(0) => index!
    (matches! and index! < leftLength) -> while {
        left -> byte(index!) => leftByte!
        right -> byte(index!) => rightByte!
        (leftByte! >= UInt8(65) and leftByte! <= UInt8(90)) -> if { leftByte! + UInt8(32) => leftByte! }
        (rightByte! >= UInt8(65) and rightByte! <= UInt8(90)) -> if { rightByte! + UInt8(32) => rightByte! }
        leftByte! != rightByte! -> if { false => matches! }
        index! + UIntSize(1) => index!
    }
    matches!
}

